#include <iostream>
#include <vector>

// 반복문을 사용하여 n번째 세 자리 피보나치 수를 구하는 함수
int threefibonacci(int n) {
    // 기저 케이스: 첫 세 자리 피보나치 수열의 시작은 0, -1, -1
    std::vector<int> sequence = {0, -1, -1};
    if (n <= 2) {
        return sequence[n];
    }
    // 반복문을 사용하여 n 번째 세 자리 피보나치 수를 계산
    for (int i = 3; i <= n; ++i) {
        int next_number = sequence[i - 1] + sequence[i - 2] + sequence[i - 3];
        sequence.push_back(next_number);
    }
    return sequence[n];
}

int main() {
    int n;
    std::cout << "세 자리 피보나치 수를 구할 항을 입력하세요: ";
    std::cin >> n;

    int result = threefibonacci(n);
    std::cout << "세 자리 피보나치 수(n=" << n << ") = " << result << std::endl;

    return 0;
}
```

